import { Entity, ObjectIdColumn, Column } from 'typeorm'
import { uuidv4 } from '@utils'
import { Exclude, Expose, plainToClass } from 'class-transformer'

import {
	Gender,
	Local,
	Google,
	Facebook,
	UserType
} from '../generator/graphql.schema'

@Entity({
	name: 'users',
	orderBy: {
		createdAt: 'ASC'
	}
})
export class User {
	@Expose()
	@ObjectIdColumn()
	_id: string

	@Expose()
	@Column()
	local: Local

	@Expose()
	@Column()
	google: Google

	@Expose()
	@Column()
	facebook: Facebook

	@Expose()
	@Column()
	firstName: string

	@Expose()
	@Column()
	lastName: string

	@Expose()
	@Column()
	avatar: string

	@Expose()
	@Column()
	resetPasswordToken: string

	@Expose()
	@Column()
	resetPasswordExpires: number

	// @Expose()
	// get fullName(): string {
	// 	return `${this.firstName} ${this.lastName}`;
	// }

	// @Transform(role => role.name)
	// role: RoleEntity;

	@Expose()
	@Column()
	gender: Gender

	@Expose()
	@Column()
	isVerified: boolean

	@Expose()
	@Column()
	isOnline: boolean

	@Expose()
	@Column()
	isLocked: boolean

	@Expose()
	@Column()
	reason: string

	@Expose()
	@Column()
	isActive: boolean

	@Expose()
	@Column()
	stripeId: string

	@Expose()
	@Column()
	ccLast4: string

	@Expose()
	@Column()
	type: UserType

	@Expose()
	@Column()
	createdAt: number
	@Expose()
	@Column()
	updatedAt: number

	constructor(user: Partial<User>) {
		if (user) {
			Object.assign(
				this,
				plainToClass(User, user, {
					excludeExtraneousValues: true
				})
			)
			this._id = this._id || uuidv4()
			this.isVerified =
				this.isVerified !== undefined
					? this.isVerified
					: this.google || this.facebook
					? true
					: false
			this.isOnline = this.isOnline !== undefined ? this.isOnline : false
			this.isLocked = this.isLocked !== undefined ? this.isLocked : false
			this.reason = this.reason || ''
			this.isActive = this.isActive !== undefined ? this.isActive : true
			this.type = this.type || UserType.BASIC
			this.createdAt = this.createdAt || +new Date()
			this.updatedAt = +new Date()
		}
	}
}

import { Resolver, Query, Mutation, Args } from '@nestjs/graphql'
import { getMongoRepository } from 'typeorm'

import { Permission } from '@entities'
import { ApolloError } from 'apollo-server-core'
import { PermissionInput } from '../generator/graphql.schema'

@Resolver('Permission')
export class PermissionResolver {
	@Query()
	async permissions(): Promise<Permission[]> {
		return getMongoRepository(Permission).find({
			where: { isActive: true },
			cache: true
		})
	}

	@Mutation()
	async createPermission(
		@Args('input') input: PermissionInput
	): Promise<boolean> {
		try {
			const data = await getMongoRepository(Permission).findOne({
				code: input.code,
				isActive: true
			})
			if (!data) {
				return (await getMongoRepository(Permission).save(
					new Permission({ ...input })
				))
					? true
					: false
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}

	@Mutation()
	async updatePermission(
		@Args('id') id: string,
		@Args('input') input: PermissionInput
	): Promise<boolean> {
		try {
			const permission = await getMongoRepository(Permission).findOne({
				_id: id,
				isActive: true
			})
			if (permission) {
				const data = await getMongoRepository(Permission).findOne({
					code: input.code,
					isActive: true
				})
				if (!data || data._id === id) {
					return (await getMongoRepository(Permission).save(
						new Permission({ ...permission, ...input })
					))
						? true
						: false
				} else {
					return false
				}
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}

	@Mutation()
	async deletePermission(@Args('id') id: string) {
		try {
			const data = await getMongoRepository(Permission).findOne({ _id: id })
			if (data) {
				return (await getMongoRepository(Permission).save(
					new Permission({ ...data, isActive: false })
				))
					? true
					: false
			} else {
				return false
			}
		} catch (error) {
			throw new ApolloError(error)
		}
	}
}

import { Resolver, Mutation, Args, Query, Context } from '@nestjs/graphql'
import { getMongoRepository } from 'typeorm'
import { ForbiddenError } from 'apollo-server-core'

import { Room, User } from '@entities'
import { CreateRoomInput } from '../generator/graphql.schema'

@Resolver('Room')
export class RoomResolver {
	@Query(() => [Room])
	async rooms(): Promise<Room[]> {
		return getMongoRepository(Room).find({
			cache: true
		})
	}

	@Query(() => Room)
	async room(@Args('_id') _id: string): Promise<Room> {
		const room = await getMongoRepository(Room).findOne({
			_id
		})

		if (!room) {
			throw new ForbiddenError('Room not found.')
		}

		return getMongoRepository(Room).findOne({
			_id
		})
	}

	@Mutation(() => Room)
	async createRoom(
		@Args('input') input: CreateRoomInput,
		@Context('currentUser') currentUser: User
	): Promise<Room> {
		const { title, userIds } = input

		if (userIds.length === 0) {
			throw new ForbiddenError('Room must have at least 2 people.')
		}

		const existedUserIds = await getMongoRepository(User).find({
			where: { _id: { $in: userIds, $ne: currentUser._id } }
		})

		if (userIds.length !== existedUserIds.length) {
			throw new ForbiddenError('One of userIds is invalid.')
		}

		return await getMongoRepository(Room).save(
			new Room({ title, users: [...existedUserIds, currentUser] })
		)
	}

	@Mutation(() => Boolean)
	async joinRoom(
		@Args('_id') _id: string,
		@Context('currentUser') currentUser: User
	): Promise<boolean> {
		const room = await getMongoRepository(Room).findOne({
			_id
		})

		if (!room) {
			throw new ForbiddenError('Room not found.')
		}

		const rs = room.users.filter(item => item._id === currentUser._id)

		if (rs.length > 0) {
			throw new ForbiddenError('You joined the room.')
		}

		room.users = [...room.users, currentUser]

		return getMongoRepository(Room).save(room) ? true : false
	}

	@Mutation(() => Boolean)
	async leaveRoom(
		@Args('_id') _id: string,
		@Context('currentUser') currentUser: User
	): Promise<boolean> {
		const room = await getMongoRepository(Room).findOne({
			_id
		})

		if (!room) {
			throw new ForbiddenError('Room not found.')
		}

		const rs = room.users.filter(item => item._id === currentUser._id)

		if (rs.length === 0) {
			throw new ForbiddenError('You are not in the room.')
		}

		room.users = room.users.filter(item => item._id !== currentUser._id)

		return getMongoRepository(Room).save(room) ? true : false
	}
}

import { Message } from '@google-cloud/pubsub';
import { PubsubBatchManagerConfigurationInvalidError } from './pubsub-configuration.errors';
import { promiseWithResolvers } from './utils';

type BatchItem = {
  message: Message;
  deferred: ReturnType<typeof promiseWithResolvers<void>>;
};

export interface BatchManagerOptions {
  maxMessages: number;
  maxWaitTimeMilliseconds: number;
}

export class PubsubSubscriptionBatchManager {
  private buffer: BatchItem[] = [];
  private timer: NodeJS.Timeout | null = null;

  private listener: ((batch: BatchItem[]) => Promise<void>) | null = null;

  constructor(private readonly options?: BatchManagerOptions) {
    const maxMessages = options?.maxMessages;

    if (!Number.isInteger(maxMessages) || maxMessages! <= 0) {
      throw new PubsubBatchManagerConfigurationInvalidError({
        key: 'subscription.batchManagerOptions.maxMessages',
        value: maxMessages,
        reason: 'Must be a positive integer greater than 0.',
      });
    }

    const maxWaitTimeMilliseconds = options?.maxWaitTimeMilliseconds;

    if (
      !Number.isInteger(maxWaitTimeMilliseconds) ||
      maxWaitTimeMilliseconds! <= 0
    ) {
      throw new PubsubBatchManagerConfigurationInvalidError({
        key: 'subscription.batchManagerOptions.maxWaitTimeMilliseconds',
        value: maxWaitTimeMilliseconds,
        reason: 'Must be a positive integer greater than 0.',
      });
    }
  }

  public on(handler: (batch: BatchItem[]) => Promise<void>) {
    this.listener = handler;
  }

  public add(message: Message) {
    const deferred = promiseWithResolvers<void>();

    this.buffer.push({ deferred, message });

    if (this.buffer.length >= this.options!.maxMessages) {
      this.flush();
    } else if (!this.timer) {
      this.timer = setTimeout(() => {
        void this.flush();
      }, this.options!.maxWaitTimeMilliseconds);
    }

    return deferred.promise;
  }

  public async flush() {
    if (this.timer) {
      clearTimeout(this.timer);
      this.timer = null;
    }

    if (this.buffer.length === 0) {
      return;
    }

    const batch = this.buffer;
    this.buffer = [];

    if (this.listener) {
      await this.listener(batch);
    }
  }
}

import { Injectable } from '@nestjs/common';
import { Buffer } from 'node:buffer';
import Stripe from 'stripe';
import {
  InjectStripeClient,
  InjectStripeModuleConfig,
} from './stripe.decorators';
import {
  StripeModuleConfig,
  StripeSecrets,
  StripeWebhookMode,
} from './stripe.interfaces';

@Injectable()
export class StripePayloadService {
  private readonly stripeSecrets: StripeSecrets;
  private readonly stripeThinSecrets: StripeSecrets;

  constructor(
    @InjectStripeModuleConfig()
    readonly config: StripeModuleConfig,
    @InjectStripeClient()
    private readonly stripeClient: Stripe,
  ) {
    this.stripeSecrets = config.webhookConfig?.stripeSecrets || {};
    this.stripeThinSecrets = config.webhookConfig?.stripeThinSecrets || {};
  }

  async tryHydratePayload(
    signature: string,
    payload: Buffer,
    mode: StripeWebhookMode,
  ): Promise<{ type: string }> {
    const decodedPayload = JSON.parse(
      Buffer.isBuffer(payload) ? payload.toString('utf8') : payload,
    );

    const secrets = this.getWebhookSecrets(mode);
    const secretToUse = this.getWebhookSecret(decodedPayload, secrets);

    switch (mode) {
      case StripeWebhookMode.SNAPSHOT:
        return this.stripeClient.webhooks.constructEventAsync(
          payload,
          signature,
          secretToUse,
        );

      case StripeWebhookMode.THIN:
        return this.stripeClient.webhooks.constructEventAsync(
          payload,
          signature,
          secretToUse,
        );
    }
  }

  private getWebhookSecrets(mode: StripeWebhookMode) {
    switch (mode) {
      case StripeWebhookMode.SNAPSHOT:
        return this.stripeSecrets;
      case StripeWebhookMode.THIN:
        return this.stripeThinSecrets;
    }
  }

  private getWebhookSecret(
    evt: Stripe.EventBase,
    secrets: StripeSecrets,
  ): string {
    let secret: string | undefined;

    if (!evt.account) {
      secret = evt.livemode ? secrets.account : secrets.accountTest;
    } else {
      secret = evt.livemode ? secrets.connect : secrets.connectTest;
    }

    if (!secret) {
      throw new Error(
        'Could not determine which secret to use for this webhook call!',
      );
    }

    return secret;
  }
}

import { SetMetadata } from '@nestjs/common';

import { GoogleCloudPubsubMessage, PubsubTopicConfiguration } from './client';
import {
  GOOGLE_CLOUD_PUBSUB_BATCH_SUBSCRIBE,
  GOOGLE_CLOUD_PUBSUB_SUBSCRIBE,
} from './google-cloud-pubsub.constants';

export interface PubsubSubscribeMetadata {
  subscription: string;
  topic: string;
}

export interface PubsubBatchSubscribeMetadata {
  subscription: string;
  topic: string;
}

export function createSubscribeDecorator<
  Topics extends readonly PubsubTopicConfiguration[],
  PayloadMap extends Record<string, unknown>,
>() {
  type SubscriptionNamePerTopicName<TopicName extends keyof PayloadMap> =
    Extract<
      Topics[number],
      { name: TopicName }
    >['subscriptions'][number]['name'];

  return <TopicName extends keyof PayloadMap & string>(
    topic: TopicName,
    subscription: SubscriptionNamePerTopicName<TopicName>,
  ) => {
    return (
      target: object,
      key: string | symbol,
      descriptor: TypedPropertyDescriptor<
        (
          payload: GoogleCloudPubsubMessage<PayloadMap[TopicName]>,
        ) => Promise<void>
      >,
    ) => {
      SetMetadata(GOOGLE_CLOUD_PUBSUB_SUBSCRIBE, {
        subscription,
        topic,
      } as PubsubSubscribeMetadata)(target, key, descriptor);

      return descriptor;
    };
  };
}

export function createBatchSubscribeDecorator<
  Topics extends readonly PubsubTopicConfiguration[],
  PayloadMap extends Record<string, unknown>,
>() {
  type SubscriptionNamePerTopicName<TopicName extends keyof PayloadMap> =
    Extract<
      Topics[number],
      { name: TopicName }
    >['subscriptions'][number]['name'];

  return <TopicName extends keyof PayloadMap & string>(
    topic: TopicName,
    subscription: SubscriptionNamePerTopicName<TopicName>,
  ) => {
    return (
      target: object,
      key: string | symbol,
      descriptor: TypedPropertyDescriptor<
        (
          payload: GoogleCloudPubsubMessage<PayloadMap[TopicName]>[],
        ) => Promise<void>
      >,
    ) => {
      SetMetadata(GOOGLE_CLOUD_PUBSUB_BATCH_SUBSCRIBE, {
        subscription,
        topic,
      } as PubsubBatchSubscribeMetadata)(target, key, descriptor);

      return descriptor;
    };
  };
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { NestCasbinService } from 'nestjs-casbin';
import { defaultResourceBuilder } from './helper';

@Injectable()
export class RolesService implements OnModuleInit {
  logger = new Logger(this.constructor.name);
  constructor(private readonly userEnforcer: NestCasbinService) {}

  async populateRoles() {
    const resources = defaultResourceBuilder();
    for (const res of resources) {
      if (res.actions.read.length > 0) {
        for (const a of res.actions.read) {
          try {
            const check = await this.userEnforcer.hasPolicy(
              a,
              res.name,
              'read',
            );
            if (!check) {
              await this.userEnforcer.addPolicy(a, res.name, 'read');
            }
          } catch (e) {
            this.logger.error(e);
          }
        }
      }

      if (res.actions.create.length > 0) {
        for (const a of res.actions.create) {
          try {
            const check = await this.userEnforcer.hasPolicy(
              a,
              res.name,
              'create',
            );
            if (!check) {
              await this.userEnforcer.addPolicy(a, res.name, 'create');
            }
          } catch (e) {
            this.logger.error(e);
          }
        }
      }

      if (res.actions.delete.length > 0) {
        for (const a of res.actions.delete) {
          try {
            const check = await this.userEnforcer.hasPolicy(
              a,
              res.name,
              'delete',
            );
            if (!check) {
              await this.userEnforcer.checkPermission(a, res.name, 'delete');
            }
          } catch (e) {
            this.logger.error(e);
          }
        }
      }

      if (res.actions.update.length > 0) {
        for (const a of res.actions.update) {
          try {
            const check = await this.userEnforcer.hasPolicy(
              a,
              res.name,
              'update',
            );
            if (!check) {
              await this.userEnforcer.addPolicy(a, res.name, 'update');
            }
          } catch (e) {
            this.logger.error(e);
          }
        }
      }
    }
  }

  onModuleInit(): any {
    // this.populateRoles();
  }
}

import { CommandHandler, EventBus, ICommandHandler } from '@nestjs/cqrs';
import { TenantRepository } from '@ultimatebackend/repository';
import {
  AcceptMemberInvitationResponse,
  Member,
} from '@ultimatebackend/proto-schema/tenant';
import { AcceptInvitationCommand } from '../../impl';
import { RolesRpcClientService } from '@ultimatebackend/core';
import { JwtService } from '@nestjs/jwt';
import { RpcException } from '@nestjs/microservices';
import { InvitationStatus } from '@ultimatebackend/contracts';
import { Logger } from '@nestjs/common';

@CommandHandler(AcceptInvitationCommand)
export class AcceptInvitationHandler
  implements ICommandHandler<AcceptInvitationCommand> {
  logger = new Logger(this.constructor.name);

  constructor(
    private readonly tenantRepository: TenantRepository,
    private readonly eventBus: EventBus,
    private readonly roleService: RolesRpcClientService,
    private readonly jwtService: JwtService,
  ) {}

  async execute(
    command: AcceptInvitationCommand,
  ): Promise<AcceptMemberInvitationResponse> {
    this.logger.log(`'Async '${command.constructor.name}...`);
    const { input, user } = command;

    try {
      // @ts-ignore
      const payload: {
        tenantId: string;
        memberId: string;
      } = await this.jwtService.decode(input.token);
      if (!payload) {
        throw new RpcException('Invalid invitation token');
      }

      const tenant = await this.tenantRepository.findOneAndUpdate({
        conditions: {
          normalizedName: payload.tenantId,
          member: {
            $elemMatch: {
              id: payload.memberId,
              status: InvitationStatus.PENDING,
            },
          },
        },
        updates: {
          $set: {
            'members.$.status': InvitationStatus.ACCEPTED,
          },
        },
      });

      if (!tenant) {
        throw new RpcException('Invitation for tenant not found');
      }
      const member = tenant.members.reduce(
        (previousValue) =>
          previousValue.id === payload.memberId && previousValue,
      );

      await this.roleService.svc
        .addUserToRole({
          role: member.role,
          domain: tenant.normalizedName,
          actor: 'user',
          userId: user.id.toString(),
        })
        .toPromise();

      return {
        member: (member as unknown) as Member,
      };
    } catch (e) {
      this.logger.error(e);
      throw new RpcException(e);
    }
  }
}

import { IPermission, IResource } from '../';
import {
  ClassType,
  DecoratorTypeOptions,
  ensureReflectMetadataExists,
} from '@ultimatebackend/common';

export class MetadataStorage {
  fields: FilterableMetadata[] = [];
  resources: ResourceMetadata[] = [];
  permissions: PermissionMetadata[] = [];
  instances: InstanceMetadata[] = [];

  constructor() {
    ensureReflectMetadataExists();
  }

  collectClassFieldMetadata(definition: FilterableMetadata) {
    this.fields.push(definition);
  }

  collectPermissionsMetadata(definition: PermissionMetadata) {
    this.permissions.push(definition);
  }

  collectResourcesMetadata(definition: ResourceMetadata) {
    this.resources.push(definition);
  }

  collectInstanceMetadata(definition: InstanceMetadata) {
    this.instances.push(definition);
  }

  clear() {
    this.fields = [];
    this.resources = [];
    this.permissions = [];
    this.instances = [];
  }
}

export interface FilterableMetadata {
  getType?: TypeValueThunk;
  typeOptions?: TypeOptions;
  getObjectType?: ClassTypeResolver;
  methodName: string;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  filterSchema?: any;
}

// tslint:disable-next-line:ban-types
export type TypeValue = ClassType | Function | object | symbol;
export type TypeValueThunk = (type?: void) => TypeValue;
export type ClassTypeResolver = (of?: void) => ClassType;

export interface TypeOptions extends DecoratorTypeOptions {
  array?: boolean;
  isEnum?: boolean;
  arrayDepth?: number;
}

export interface PermissionMetadata {
  getType?: TypeValueThunk;
  typeOptions?: TypeOptions;
  getObjectType?: ClassTypeResolver;
  methodName: string;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  filterSchema?: any;
  options?: IPermission;
}

export interface ResourceMetadata {
  prototype?: any;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  options?: IResource;
}

export interface InstanceMetadata {
  prototype?: any;
  getObjectType?: ClassTypeResolver;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
}

